// frontend/src/components/ProtectedRoute.jsx
import { Navigate } from 'react-router-dom';
import { useEffect, useState } from 'react';
import api from '../services/api';

export default function ProtectedRoute({ children, adminOnly = false }) {
  const [loading, setLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);

  useEffect(() => {
    const checkAuth = async () => {
      const token = localStorage.getItem('token');
      const role = localStorage.getItem('role');
      
      console.log('🔍 ProtectedRoute - Token:', token ? 'exists' : 'none');
      console.log('🔍 ProtectedRoute - Role from localStorage:', role);
      
      if (!token) {
        setIsAuthenticated(false);
        setLoading(false);
        return;
      }

      try {
        const user = await api.getCurrentUser();
        console.log('🔍 ProtectedRoute - User from API:', user);
        
        setIsAuthenticated(true);
        
        // Check if admin
        const userRole = user.role || role || 'user';
        setIsAdmin(userRole === 'admin');
        
        console.log('🔍 ProtectedRoute - IsAdmin:', userRole === 'admin');
        console.log('🔍 ProtectedRoute - adminOnly prop:', adminOnly);
        
      } catch (error) {
        console.error('🔍 ProtectedRoute - Auth error:', error);
        localStorage.removeItem('token');
        localStorage.removeItem('role');
        localStorage.removeItem('email');
        setIsAuthenticated(false);
      } finally {
        setLoading(false);
      }
    };

    checkAuth();
  }, []);

  if (loading) {
    return <div>Loading...</div>;
  }

  if (!isAuthenticated) {
    console.log('🔍 ProtectedRoute - Not authenticated, redirecting to /auth');
    return <Navigate to="/auth" replace />;
  }

  // Check admin-only access
  if (adminOnly && !isAdmin) {
    console.log('🔍 ProtectedRoute - Not admin, redirecting to /dashboard');
    return <Navigate to="/dashboard" replace />;
  }

  console.log('🔍 ProtectedRoute - Rendering children');
  return children;
}
